import random
import json

class Chabot:
    def __init__(self, model_name: str):
        self.model_name = model_name

    def select_model(self, models: list):
        if models:
            choice = random.choice(models)
            return choice
        return 'model-1'  # Fallback to model-1

    def run_interaction(self, model: str):
        """Perform a limited set of interactions with the chosen model."""
        responses = self._interact_with_bot(model)
        return responses

def format_responses(responses):
    """Format individual chatbot responses into a structured JSON object.

    Returns a list where each element is a dictionary with keys:
    - "content": str
    - "role": str (can be "assistant", "function", etc.)
    - "extra": any (if response has additional properties)

    The list is guaranteed to have an even number of elements (pairs of messages).
    """
    # Build list of dicts
    processed_responses = []
    for i in range(0, len(responses), 2):
        if i + 1 < len(responses):  # Make sure we have a next message
            msg_content = responses[i]
            next_msg = responses[i + 1]

            processed_dict = {
                "content": msg_content,
                "role": next_msg['role'],
                "extra": None  # Store extra info in next message if possible
            }
            processed_responses.append(processed_dict)

    return processed_responses


